shape.script:
function getHandles(params) {
    let innerRadius = params.innerRadius;
    let outerRadius = params.outerRadius;
    let pointCount = params.pointCount;
    let radsPerPoint = 2.0*Math.PI/pointCount;
    let radsPerHalfPoint = radsPerPoint / 2.0;
    let offsetAngle = params.offsetAngle * Math.PI / 180.0;

    let outerHandleAngle = Math.PI/2.0 + offsetAngle - radsPerPoint * Math.floor(pointCount/3);
    let innerHandleAngle = radsPerPoint * Math.floor(pointCount*2/3) + Math.PI/2.0 + offsetAngle - radsPerHalfPoint;

    return {
        in: [innerRadius*Math.cos(innerHandleAngle),innerRadius*-Math.sin(innerHandleAngle)],
        out: [outerRadius*Math.cos(outerHandleAngle),outerRadius*-Math.sin(outerHandleAngle)],
        a: [outerRadius*Math.cos(offsetAngle + Math.PI/2.0),outerRadius*-Math.sin(offsetAngle + Math.PI/2.0)],
    }
}

function getPath(params) {
    let innerRadius = params.innerRadius;
    let outerRadius = params.outerRadius;
    let pointCount = params.pointCount;
    let offsetAngle = params.offsetAngle * Math.PI / 180.0;
    let points = [];
    let radsPerPoint = 2.0*Math.PI/pointCount;
    let radsPerHalfPoint = radsPerPoint / 2.0;
    let innerCirc = innerRadius * 2.0 * Math.PI;
    let segLen = innerCirc / pointCount;
    let pw = segLen / 2.0;
    for( let i=0; i<pointCount; i++ ) {
        let angle = radsPerPoint*i + Math.PI/2.0 + offsetAngle;
        let x = outerRadius*Math.cos(angle);
        let y = outerRadius*-Math.sin(angle);
        let perpX = y;
        let perpY = -x;
        let perpLen = Math.hypot(perpX,perpY);
        perpX /= perpLen;
        perpY /= perpLen;
        let x0 = x - perpX * pw;
        let y0 = y - perpY * pw;
        let x2 = x + perpX * pw;
        let y2 = y + perpY * pw;
        //points.push([x0,y0]);
        //points.push([x,y]);
        points.push({
            in:[x0,y0],
            p:[x,y],
            out:[x2,y2]
        });
        //points.push([x2,y2]);
        angle += radsPerHalfPoint;
        points.push([innerRadius*Math.cos(angle),innerRadius*-Math.sin(angle)]);
    }
    points.push({closed:true});
    return points;
}
